SELECT ?scorer ?honour ?honourLabel WHERE {
  ?match wdt:P2237 wd:Q172575 ;
         wdt:P2236 wd:Q148153 ;
         wdt:P31 wd:Q2946613 ;
         wdt:P125 wd:Q485205 ;
         wdt:P278 "1-1" ;
         wdt:P585 ?time .
  FILTER (YEAR(?time) = 1983 || YEAR(?time) = 1984)
  ?match wdt:P1623 ?scorer .
  ?scorer wdt:P54 wd:Q148153 .
  ?scorer wdt:P1229 ?honour .
  OPTIONAL { ?honour rdfs:label ?honourLabel . FILTER (LANG(?honourLabel) = "en") }
}

